#include<bits/stdc++.h>
using namespace  std;
int  main(){
	long long n,a,shu1[1000]={0},shu2[1000]={0};
	string b,c,e,fu1[1000],fu2[1000];
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a>>b>>c>>c>>e;
		shu1[i]=a;
		fu1[i]=b;
		fu2[i]=e;
		if(b=="km"){
			if(e=="m"){
				shu2[i]=a*1000;
			}else{
				shu2[i]=a*1000000;
			}
		}
		if(b=="m"){
			if(e=="mm"){
				shu2[i]=a*1000;
			}
		}
		if(b=="kg"){
			if(e=="g"){
				shu2[i]=a*1000;
			}else{
				if(e=="mg"){
					shu2[i]=a*1000000;
				}
			}
		}
		if(b=="g"){
			if(e=="mg"){
				shu2[i]=a*1000;
			}
		}
	}
	for(int i=0;i<n;i++){
		cout<<shu1[i]<<" "<<fu1[i]<<" = "<<shu2[i]<<" "<<fu2[i]<<endl; 
	}
return 0;
}
